      { icone: "🌭", titre: "Choisir les saucisses", detail: "BRATWURST allemandes idéalement (Nüremberg, Thüringen) ou à défaut, saucisses de Strasbourg ou Frankfurt. ASTUCE : faire des entailles diagonales SI pas de boyaux fragiles, sinon laisser entières.", badge: "⏱ 2 min" },
      { icone: "🍳", titre: "Saisir les saucisses", detail: "Dans une grande poêle, chauffer 1 cs d'huile. Faire dorer les saucisses 8-10 min en les retournant régulièrement. Elles doivent être DORÉES partout et bien chaudes à cœur.", badge: "⏱ 10 min" },
      { icone: "🧅", titre: "Préparer l'oignon", detail: "Émincer finement 1 petit oignon. Dans une casserole, le faire revenir 5 min dans 1 cs d'huile jusqu'à translucide.", badge: "⏱ 5 min" },
      { icone: "🌶️", titre: "Toaster les épices", detail: "SECRET DU CURRYWURST : ajouter le curry en poudre et le paprika à l'oignon, faire revenir 30 SECONDES seulement (pas plus, sinon ça brûle). C'est ce qui réveille leurs arômes.", badge: "⏱ 1 min" },
      { icone: "🍅", titre: "Sauce currywurst", detail: "Ajouter le ketchup, l'eau, le vinaigre de vin blanc, le sucre roux. Mélanger énergiquement. Mijoter 5 min à feu doux. Doit être ÉPAISSE et ONCTUEUSE. Saler/poivrer.", badge: "⏱ 5 min" },
      { icone: "🔪", titre: "Trancher les saucisses", detail: "ASTUCE BERLINOISE : couper les saucisses cuites en TRANCHES DE 2cm en biais. C'est essentiel — pas de currywurst sans tranches !", badge: "⏱ 2 min" },
      { icone: "🍽️", titre: "Dressage authentique", detail: "Dans une assiette : tranches de saucisse, NAPPER GÉNÉREUSEMENT de sauce. Saupoudrer encore d'un peu de curry en poudre sur le dessus (visuel !).", badge: "⏱ 1 min" },
      { icone: "🍟", titre: "Accompagnement", detail: "Servir avec : pommes frites belges (Pommes Frites mit Mayo), brötchen (petits pains allemands) ou pain de seigle. Sauce mayo à côté. Bière fraîche.", badge: null }
