      { nb: 12, pommedeterre: "1.8 kg", oeufs: "18", oignon: "600 g", huiledolive: "360 ml", sel: "12 g", poivre: "6 g", ail: "6", persil: "24 g" },
      { nb: 13, pommedeterre: "1.9 kg", oeufs: "975 g", oignon: "650 g", huiledolive: "390 ml", sel: "13 g", poivre: "6 g", ail: "32 g", persil: "26 g" },
      { nb: 14, pommedeterre: "2.1 kg", oeufs: "21", oignon: "700 g", huiledolive: "420 ml", sel: "14 g", poivre: "7 g", ail: "7", persil: "28 g" },
      { nb: 15, pommedeterre: "2.2 kg", oeufs: "1125 g", oignon: "750 g", huiledolive: "450 ml", sel: "15 g", poivre: "8 g", ail: "38 g", persil: "30 g" }
