      { nb: 15, fromagebeaufort: "1.1 kg", fromagecomte: "1.1 kg", fromageemmental: "900 g", vinblanc: "750 ml", kirsch: "75 ml", ail: "38 g", painrassis: "2.2 kg", poivre: "15 g" }
